import java.io.BufferedInputStream
private class FS{val input=BufferedInputStream(System.`in`);val b=ByteArray(1 shl 16);var l=0;var p=0;fun rb():Int{if(p>=l){l=input.read(b);p=0;if(l<=0)return -1};return b[p++].toInt()}fun nextInt():Int{var c=rb();while(c<=32&&c>=0)c=rb();var sign=1;if(c=='-'.code){sign=-1;c=rb()};var v=0;while(c>32){v=v*10+c-'0'.code;c=rb()};return v*sign}}
fun solve(m:Array<IntArray>, k:Int):Int{val rows=m.size;val cols=m[0].size;var best=Int.MIN_VALUE;for(top in 0 until rows){val sums=IntArray(cols);for(bot in top until rows){for(c in 0 until cols)sums[c]+=m[bot][c];val pre=mutableListOf(0);var cur=0;for(x in sums){cur+=x;val target=cur-k;var lo=0;var hi=pre.size;while(lo<hi){val md=(lo+hi)/2;if(pre[md]<target)lo=md+1 else hi=md};if(lo<pre.size)best=maxOf(best,cur-pre[lo]);lo=0;hi=pre.size;while(lo<hi){val md=(lo+hi)/2;if(pre[md]<cur)lo=md+1 else hi=md};pre.add(lo,cur)}}};return best}
fun main(){val fs=FS();val t=fs.nextInt();val out=StringBuilder();repeat(t){tc->val r=fs.nextInt();val c=fs.nextInt();val m=Array(r){IntArray(c){fs.nextInt()}};val k=fs.nextInt();if(tc>0)out.append("\n\n");out.append(solve(m,k))};print(out)}
